import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import type { ZodType } from 'zod'
import { deleteDocument, getDocument, listDocuments, uploadAndConvert } from './services/documents.ts'
import { approvePlan, createPlan, getPlan, getPlansForDocument, revisePlan } from './services/plans.ts'
import * as quiz from './services/quizzes.ts'
import { completeAttempt, getAttempt, listAttempts } from './services/attempts.ts'

const IdParam = z.object({ id: z.coerce.number() })

export async function routes(app: FastifyInstance) {
  app.get('/api/documents', () => listDocuments())

  app.get('/api/documents/:id', async (req, reply) => {
    const { id } = validate(IdParam, req.params)
    const doc = await getDocument(id)
    if (!doc) return reply.code(404).send({ error: 'Document not found' })
    return doc
  })

  app.delete('/api/documents/:id', async (req, reply) => {
    const { id } = validate(IdParam, req.params)
    const deleted = await deleteDocument(id)
    if (!deleted) return reply.code(404).send({ error: 'Document not found' })
    return reply.code(204).send()
  })

  app.get('/api/documents/:id/plans', async (req) => {
    const { id } = validate(IdParam, req.params)
    return getPlansForDocument(id)
  })

  app.post('/api/documents/:id/plans', async (req, reply) => {
    const { id } = validate(IdParam, req.params)
    const plan = await createPlan(id)
    return reply.code(201).send(plan)
  })

  app.post('/api/documents/upload', async (req, reply) => {
    const part = await req.file()
    if (!part) {
      return reply.code(400).send({ error: 'No file provided' })
    }
    const allowed = ['.pdf']
    const lower = part.filename.toLowerCase()
    if (!allowed.some((ext) => lower.endsWith(ext))) {
      return reply.code(400).send({ error: 'Only PDF files are supported' })
    }
    const buffer = await part.toBuffer()
    const doc = await uploadAndConvert(part.filename, buffer)
    return reply.code(201).send(doc)
  })

  app.get('/api/lesson-plans/:id', async (req, reply) => {
    const { id } = validate(IdParam, req.params)
    const plan = await getPlan(id)
    if (!plan) return reply.code(404).send({ error: 'Plan not found' })
    return plan
  })

  app.post('/api/lesson-plans/:id/approve', async (req) => {
    const { id } = validate(IdParam, req.params)
    return approvePlan(id)
  })

  const RevisePlanBody = z.object({ feedback: z.string().min(1) })

  app.post('/api/lesson-plans/:id/revise', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { feedback } = validate(RevisePlanBody, req.body)
    return revisePlan(id, feedback)
  })

  app.get('/api/lesson-plans/:id/quizzes', async (req) => {
    const { id } = validate(IdParam, req.params)
    return quiz.getAllQuizzes(id)
  })

  const CreateQuizBody = z.object({ objectiveIndex: z.number(), questionIndex: z.number() })

  app.post('/api/lesson-plans/:id/quizzes', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { objectiveIndex, questionIndex } = validate(CreateQuizBody, req.body)
    return quiz.getOrCreateQuiz(id, objectiveIndex, questionIndex)
  })

  app.post('/api/quizzes/:id/explain', async (req) => {
    const { id } = validate(IdParam, req.params)
    return quiz.getExplanation(id)
  })

  const CheckAnswerBody = z.object({ learnerIndex: z.number() })

  app.post('/api/quizzes/:id/check', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { learnerIndex } = validate(CheckAnswerBody, req.body)
    return quiz.checkAnswer(id, learnerIndex)
  })

  const HintBody = z.object({ previousGuessIndex: z.number().nullable().optional() })

  app.post('/api/quizzes/:id/hint', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { previousGuessIndex } = validate(HintBody, req.body)
    const hint = await quiz.getHint(id, previousGuessIndex ?? null)
    return { hint }
  })

  const LearnMoreBody = z.object({
    learnerQuestion: z.string(),
    history: z.array(z.object({ role: z.enum(['user', 'assistant']), content: z.string() })).optional()
  })

  app.post('/api/quizzes/:id/ai-help', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { learnerQuestion, history } = validate(LearnMoreBody, req.body)
    const message = await quiz.getAiHelp(id, learnerQuestion, history ?? [])
    return { message }
  })

  const CompleteBody = z.object({
    answers: z.array(z.object({ quizId: z.number(), learnerIndex: z.number().nullable(), attempts: z.number() }))
  })

  app.post('/api/lesson-plans/:id/complete', async (req) => {
    const { id } = validate(IdParam, req.params)
    const { answers } = validate(CompleteBody, req.body)
    return completeAttempt(id, { answers })
  })

  app.get('/api/lesson-plans/:id/attempts', async (req) => {
    const { id } = validate(IdParam, req.params)
    return listAttempts(id)
  })

  app.get('/api/attempts/:id', async (req, reply) => {
    const { id } = validate(IdParam, req.params)
    const attempt = await getAttempt(id)
    if (!attempt) return reply.code(404).send({ error: 'Attempt not found' })
    return attempt
  })
}

function validate<T>(schema: ZodType<T>, data: unknown): T {
  return schema.parse(data)
}

import { db, type QuizQuestionRow } from '../db.ts'
import { generateQuiz } from '../ai/quiz.ts'
import { generateRetryHint, explainCorrect, aiChat } from '../ai/feedback.ts'
import { getPlan } from './plans.ts'
import { getDocumentMarkdown } from './documents.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

export interface QuizDTO {
  id: number
  objectiveIndex: number
  questionIndex: number
  objectiveText: string
  question: string
  options: string[]
  hint: string
}

export async function getOrCreateQuiz(planId: number, objectiveIndex: number, questionIndex: number): Promise<QuizDTO> {
  const plan = await getPlan(planId)
  if (!plan) throw new NotFoundError('Plan not found')
  const objective = plan.objectives[objectiveIndex]
  if (!objective) throw new NotFoundError(`Objective ${objectiveIndex} not found`)

  const existing = db
    .prepare(`SELECT * FROM quiz_questions WHERE lesson_plan_id = ? AND objective_index = ? AND question_index = ?`)
    .get(planId, objectiveIndex, questionIndex) as QuizQuestionRow | undefined

  if (existing) {
    return rowToDto(existing)
  }

  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const quiz = await generateQuiz(markdown, objective.text, objective.topic, questionIndex)

  const res = db
    .prepare(
      `INSERT INTO quiz_questions (lesson_plan_id, objective_index, question_index, objective_text, question, options, correct_index, explanation, hint)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
       RETURNING id`
    )
    .get(
      planId,
      objectiveIndex,
      questionIndex,
      objective.text,
      quiz.question,
      JSON.stringify(quiz.options),
      quiz.correct_index,
      quiz.explanation,
      quiz.hint
    ) as { id: number }

  return {
    id: res.id,
    objectiveIndex,
    questionIndex,
    objectiveText: objective.text,
    question: quiz.question,
    options: quiz.options,
    hint: quiz.hint
  }
}

export async function getAllQuizzes(planId: number): Promise<QuizDTO[]> {
  const plan = await getPlan(planId)
  if (!plan) return []
  const rows = db
    .prepare(`SELECT * FROM quiz_questions WHERE lesson_plan_id = ? ORDER BY objective_index ASC, question_index ASC`)
    .all(planId) as QuizQuestionRow[]
  return rows.map(rowToDto)
}

export async function getQuizInternal(quizId: number): Promise<QuizQuestionRow | null> {
  return (db.prepare(`SELECT * FROM quiz_questions WHERE id = ?`).get(quizId) as QuizQuestionRow | undefined) ?? null
}

export async function getHint(quizId: number, previousGuessIndex: number | null): Promise<string> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return generateRetryHint(
    markdown,
    quiz.question,
    options,
    previousGuessIndex !== null ? options[previousGuessIndex] : null
  )
}

interface ExplanationResult {
  explanation: string
  correctIndex: number
}

export async function getExplanation(quizId: number): Promise<ExplanationResult> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  const correct = options[quiz.correct_index]
  const explanation = await explainCorrect(markdown, quiz.question, options, correct, quiz.correct_index)
  return { explanation, correctIndex: quiz.correct_index }
}

export interface AnswerOutput {
  correct: boolean
}

export async function checkAnswer(quizId: number, learnerIndex: number): Promise<AnswerOutput> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const correct = learnerIndex === quiz.correct_index
  return { correct }
}

interface AI_Message {
  role: 'user' | 'assistant'
  content: string
}
export type MessageHistory = Array<AI_Message>

export async function getAiHelp(id: number, question: string, history: MessageHistory): Promise<string> {
  const quiz = await getQuizInternal(id)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return aiChat(markdown, quiz.question, options, question, history)
}

function rowToDto(row: QuizQuestionRow): QuizDTO {
  return {
    id: row.id,
    objectiveIndex: row.objective_index,
    questionIndex: row.question_index,
    objectiveText: row.objective_text,
    question: row.question,
    options: JSON.parse(row.options),
    hint: row.hint
  }
}

