import { db, type DocumentRow, type LessonPlanRow } from '../db.ts'
import { generatePlan } from '../ai/plan.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

type Difficulty = 'beginner' | 'intermediate' | 'advanced'
type PlanStatus = 'draft' | 'approved' | 'completed'

export interface Objective {
  text: string
  topic: string
  question_count: number
}

export async function createPlan(documentId: number) {
  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(documentId) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (doc.status !== 'ready' || !doc.markdown) {
    throw new BadRequestError(`Document is not ready for plan generation (status: ${doc.status})`)
  }

  const plan = await generatePlan(doc.markdown, doc.filename)
  const objectivesJson = JSON.stringify(plan.objectives)
  const res = db
    .prepare(
      `INSERT INTO lesson_plans (document_id, title, description, objectives, difficulty, status)
       VALUES (?, ?, ?, ?, ?, 'draft')
       RETURNING *`
    )
    .get(documentId, plan.title, plan.description, objectivesJson, plan.difficulty) as LessonPlanRow

  return rowToPlan(res)
}

export async function revisePlan(planId: number, feedback: string) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status !== 'draft') {
    throw new BadRequestError('Only draft lesson plans can be revised')
  }

  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(row.document_id) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (!doc.markdown) throw new BadRequestError('Document has no markdown content')

  const plan = await generatePlan(doc.markdown, doc.filename, feedback)
  const objectivesJson = JSON.stringify(plan.objectives)

  // Discard any quizzes generated for the previous draft.
  db.prepare(`DELETE FROM quiz_questions WHERE lesson_plan_id = ?`).run(planId)

  const updated = db
    .prepare(
      `UPDATE lesson_plans
       SET title = ?, description = ?, objectives = ?, difficulty = ?, revision_count = revision_count + 1, revision_feedback = ?
       WHERE id = ?
       RETURNING *`
    )
    .get(plan.title, plan.description, objectivesJson, plan.difficulty, feedback, planId) as LessonPlanRow

  return rowToPlan(updated)
}

export async function getPlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) return null
  const doc = db.prepare(`SELECT filename FROM documents WHERE id = ?`).get(row.document_id)
  return {
    ...rowToPlan(row),
    document_filename: (doc as { filename: string } | undefined)?.filename
  }
}

export async function getPlansForDocument(documentId: number) {
  const rows = db
    .prepare(`SELECT * FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC`)
    .all(documentId) as LessonPlanRow[]
  return rows.map(rowToPlan)
}

export async function approvePlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status === 'draft') {
    db.prepare(`UPDATE lesson_plans SET status = 'approved' WHERE id = ?`).run(planId)
  }
  return getPlan(planId)
}

function rowToPlan(row: LessonPlanRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as Difficulty,
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as PlanStatus,
    revision_count: row.revision_count,
    revision_feedback: row.revision_feedback,
    created_at: row.created_at
  }
}

import { createAgent } from 'langchain'
import { model } from './model.ts'
import { quizSchema, type Quiz } from './schemas.ts'

const SYSTEM = `You are a meticulous quiz author. Build a single multiple-choice question that rigorously tests ONE learning objective using ONLY information present in the provided PDF markdown.

Rules:
- The question must be grounded in the document. Do not invent facts.
- Exactly 4 options. All options should be plausible; distractors should reflect common misconceptions.
- The correct option must be unambiguous given the source material.
- The explanation must justify the correct answer using the source.
- The hint must be conceptual and NEVER reveal or hint at the correct option index or wording.
- When a question_index is provided, create a distinct question from any other index for the same objective. Vary the angle (e.g. definition, application, comparison, implication) so multiple questions on the same objective are not repetitive.`

const quizAgent = createAgent({
  model: model,
  systemPrompt: SYSTEM,
  responseFormat: quizSchema
})

export async function generateQuiz(
  markdown: string,
  objectiveText: string,
  objectiveTopic: string,
  questionIndex: number
): Promise<Quiz> {
  const message = `
Objective to assess: ${objectiveText}
Topic: ${objectiveTopic}
Question number for this objective: ${questionIndex + 1}
Source material (markdown):\n"""\n${markdown}\n"""
`
  const result = await quizAgent.invoke({
    messages: [{ role: 'user', content: message.trim() }]
  })
  return result.structuredResponse
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { Loader2 } from 'lucide-react'
import { PlanCard } from '#components/plan-card'
import { MCQWidget } from '#components/mcq-widget'
import { ObjectiveTracker, type ObjectiveStatus } from '#components/objective-tracker'
import { SummaryView } from '#components/summary-view'
import { Card, CardContent } from '#components/ui/card'
import { Progress } from '#components/ui/progress'
import * as api from '#lib/api'
import type { AttemptSummary, Objective, Plan, QuizDTO } from '#lib/types'
import { difficultyLabel } from '#lib/helpers'

type Phase = 'loading' | 'review' | 'quiz' | 'summary' | 'error'

interface AnswerState {
  quizId: number
  learnerIndex: number | null
  attempts: number
  correct: boolean
  finalized: boolean
}

interface QuestionSlot {
  objectiveIndex: number
  questionIndex: number
  objective: Objective
}

function blankAnswer(quizId: number): AnswerState {
  return {
    quizId,
    learnerIndex: null,
    attempts: 0,
    correct: false,
    finalized: false
  }
}

function slotKey(objectiveIndex: number, questionIndex: number): string {
  return `${objectiveIndex}-${questionIndex}`
}

export function LessonPage() {
  const { planId } = useParams<{ planId: string }>()
  const navigate = useNavigate()
  const [phase, setPhase] = useState<Phase>('loading')
  const [plan, setPlan] = useState<Plan | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [quizzes, setQuizzes] = useState<Record<string, QuizDTO>>({})
  const [answers, setAnswers] = useState<Record<string, AnswerState>>({})
  const [currentIdx, setCurrentIdx] = useState(0)
  const [loadingQuiz, setLoadingQuiz] = useState(false)
  const [summary, setSummary] = useState<AttemptSummary | null>(null)
  const [finishing, setFinishing] = useState(false)

  const slots = useMemo<QuestionSlot[]>(() => {
    if (!plan) return []
    return plan.objectives.flatMap((objective, objectiveIndex) =>
      Array.from({ length: objective.question_count }, (_, questionIndex) => ({
        objectiveIndex,
        questionIndex,
        objective
      }))
    )
  }, [plan])

  useEffect(() => {
    if (!planId) return
    const id = Number(planId)

    async function loadPlan() {
      const p = await api.getPlan(id)
      setPlan(p)

      if (p.status === 'draft') {
        setPhase('review')
        return
      }

      if (p.status !== 'completed') {
        setPhase('quiz')
        return
      }

      try {
        const attempts = await api.listAttempts(id)
        if (attempts.length === 0) {
          setPhase('quiz')
          return
        }
        const latest = await api.getAttempt(attempts[0].id)
        setSummary(latest)
        setPhase('summary')
      } catch {
        setPhase('quiz')
      }
    }

    loadPlan().catch((err: unknown) => {
      setError((err as Error).message)
      setPhase('error')
    })
  }, [planId])

  // Preload cached quizzes when entering the quiz phase (retest path)
  useEffect(() => {
    if (phase !== 'quiz' || !planId || !plan) return
    const id = Number(planId)
    api
      .listQuizzes(id)
      .then((existing) => {
        if (existing.length === 0) return
        const map: Record<string, QuizDTO> = {}
        for (const q of existing) {
          map[slotKey(q.objectiveIndex, q.questionIndex)] = q
        }
        setQuizzes(map)
      })
      .catch(() => {
        // ignore — we'll lazy-generate
      })
  }, [phase, planId, plan])

  const currentSlot = slots[currentIdx]
  const currentKey = currentSlot ? slotKey(currentSlot.objectiveIndex, currentSlot.questionIndex) : ''
  const currentQuiz = quizzes[currentKey]

  // Lazy-generate the quiz for the current question when needed
  useEffect(() => {
    if (phase !== 'quiz' || !plan || !planId || !currentSlot) return
    if (currentQuiz || loadingQuiz) return
    const id = Number(planId)
    setLoadingQuiz(true)
    api
      .generateQuiz(id, currentSlot.objectiveIndex, currentSlot.questionIndex)
      .then((q) => {
        setQuizzes((prev) => ({ ...prev, [slotKey(q.objectiveIndex, q.questionIndex)]: q }))
      })
      .catch((err: unknown) => {
        setError((err as Error).message)
        setPhase('error')
      })
      .finally(() => setLoadingQuiz(false))
  }, [phase, plan, planId, currentSlot, currentQuiz, loadingQuiz])

  const handleApprove = useCallback(async () => {
    if (!plan) return
    try {
      const updated = await api.approvePlan(plan.id)
      setPlan(updated)
      setPhase('quiz')
    } catch (err) {
      setError((err as Error).message)
      setPhase('error')
    }
  }, [plan])

  const handleRevise = useCallback(
    async (feedback: string) => {
      if (!plan) return
      try {
        const updated = await api.revisePlan(plan.id, feedback)
        setPlan(updated)
        // Reset any quizzes cached from the previous draft.
        setQuizzes({})
        setAnswers({})
        setCurrentIdx(0)
      } catch (err) {
        setError((err as Error).message)
        setPhase('error')
      }
    },
    [plan]
  )

  const finish = useCallback(
    async (answersToSubmit?: Record<string, AnswerState>) => {
      if (!plan || !planId || finishing) return
      setFinishing(true)
      try {
        const payload = Object.values(answersToSubmit ?? answers).map((a) => ({
          quizId: a.quizId,
          learnerIndex: a.learnerIndex,
          attempts: a.attempts
        }))
        const result = await api.completeAttempt(plan.id, payload)
        setSummary(result)
        setPhase('summary')
      } catch (err) {
        setError((err as Error).message)
        setPhase('error')
      } finally {
        setFinishing(false)
      }
    },
    [plan, planId, answers, finishing]
  )

  const advance = useCallback(() => {
    if (!plan) return
    if (currentIdx + 1 >= slots.length) {
      void finish()
    } else {
      setCurrentIdx((i) => i + 1)
    }
  }, [currentIdx, plan, slots.length, finish])

  const handleIncorrect = useCallback(
    (key: string, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[key]?.id ?? -1
        const existing = prev[key] ?? blankAnswer(quizId)
        return {
          ...prev,
          [key]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: false,
            attempts: existing.attempts + 1,
            finalized: false
          }
        }
      })
    },
    [quizzes]
  )

  const handleCorrect = useCallback(
    (key: string, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[key]?.id ?? -1
        const existing = prev[key] ?? blankAnswer(quizId)
        return {
          ...prev,
          [key]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: true,
            // attempts stays — counts only incorrect tries
            finalized: true
          }
        }
      })
    },
    [quizzes]
  )

  const handleSkip = useCallback(
    (key: string) => {
      const quizId = quizzes[key]?.id ?? -1
      const existing = answers[key] ?? blankAnswer(quizId)
      const nextAnswers = {
        ...answers,
        [key]: {
          ...existing,
          quizId,
          learnerIndex: null,
          correct: false,
          finalized: true
        }
      }
      setAnswers(nextAnswers)
      if (currentIdx + 1 >= slots.length) {
        void finish(nextAnswers)
      } else {
        setCurrentIdx((i) => i + 1)
      }
    },
    [quizzes, answers, currentIdx, slots.length, finish]
  )

  const handleRetake = useCallback(() => {
    setAnswers({})
    setQuizzes({})
    setCurrentIdx(0)
    setSummary(null)
    setPhase('quiz')
  }, [])

  if (phase === 'loading') {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="size-6 animate-spin text-primary" />
      </div>
    )
  }

  if (phase === 'error' || !plan) {
    return (
      <div className="mx-auto max-w-2xl">
        <Card>
          <CardContent className="p-8 text-center">
            <p className="text-sm font-medium text-danger">{error ?? 'Something went wrong.'}</p>
          </CardContent>
        </Card>
      </div>
    )
  }

  if (phase === 'review') {
    return <PlanCard plan={plan} onApprove={handleApprove} onRevise={handleRevise} onBack={() => navigate('/')} />
  }

  if (phase === 'summary' && summary) {
    return <SummaryView summary={summary} onRetake={handleRetake} onBackToLibrary={() => navigate('/')} />
  }

  // quiz phase
  const total = slots.length
  const answerList = slots.map((slot) => answers[slotKey(slot.objectiveIndex, slot.questionIndex)])
  const completed = answerList.filter((a) => a?.finalized).length
  const score = answerList.filter((a) => a?.correct).length
  const progressPct = total === 0 ? 0 : Math.round((completed / total) * 100)

  const statuses: ObjectiveStatus[] = plan.objectives.map((obj, objectiveIndex) => {
    let correct = 0
    let finalized = 0
    for (let q = 0; q < obj.question_count; q++) {
      const a = answers[slotKey(objectiveIndex, q)]
      if (a?.finalized) finalized += 1
      if (a?.correct) correct += 1
    }
    if (finalized === 0) return 'pending'
    if (correct === obj.question_count) return 'correct'
    if (currentSlot?.objectiveIndex === objectiveIndex) return 'current'
    if (finalized === obj.question_count) return 'skipped'
    return 'current'
  })

  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <h1 className="truncate text-xl font-bold tracking-tight">{plan.title}</h1>
            <p className="text-xs text-muted-foreground">
              {difficultyLabel(plan.difficulty)} · {completed} of {total} questions done
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {score}
              <span className="text-base text-muted-foreground">/{total}</span>
            </p>
          </div>
        </div>
        <Progress value={progressPct} />
      </div>

      <div className="grid gap-6 lg:grid-cols-[1fr_280px]">
        <div className="min-w-0">
          {currentQuiz && currentSlot ? (
            <MCQWidget
              key={currentQuiz.id}
              quiz={currentQuiz}
              objectiveNumber={currentSlot.objectiveIndex + 1}
              totalObjectives={plan.objectives.length}
              questionNumber={currentSlot.questionIndex + 1}
              totalQuestionsInObjective={currentSlot.objective.question_count}
              onCorrect={(learnerIndex) => {
                handleCorrect(currentKey, learnerIndex)
              }}
              onIncorrect={(learnerIndex) => handleIncorrect(currentKey, learnerIndex)}
              onSkip={() => handleSkip(currentKey)}
              onNext={advance}
              isLast={currentIdx === total - 1}
            />
          ) : (
            <Card>
              <CardContent className="flex flex-col items-center justify-center gap-3 p-12 text-center">
                <Loader2 className="size-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  {currentSlot ? (
                    <>
                      Generating question {currentSlot.questionIndex + 1} for path {currentSlot.objectiveIndex + 1}...
                    </>
                  ) : (
                    <>Wrapping up...</>
                  )}
                </p>
              </CardContent>
            </Card>
          )}
          {finishing && (
            <p className="mt-4 flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              Building your progress report...
            </p>
          )}
        </div>

        <aside className="lg:sticky lg:top-20 lg:self-start">
          <ObjectiveTracker objectives={plan.objectives} statuses={statuses} score={score} total={total} />
        </aside>
      </div>
    </div>
  )
}

