import { db, type DocumentRow, type LessonPlanRow } from '../db.ts'
import { generatePlan } from '../ai/plan.ts'
import { createAllQuizzes } from './quizzes.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

type Difficulty = 'beginner' | 'intermediate' | 'advanced'
type PlanStatus = 'draft' | 'approved' | 'completed'

export interface Objective {
  text: string
  topic: string
  question_count: number
}

export async function createPlan(documentId: number) {
  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(documentId) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (doc.status !== 'ready' || !doc.markdown) {
    throw new BadRequestError(`Document is not ready for plan generation (status: ${doc.status})`)
  }

  const plan = await generatePlan(doc.markdown, doc.filename)
  const objectivesJson = JSON.stringify(plan.objectives)
  const res = db
    .prepare(
      `INSERT INTO lesson_plans (document_id, title, description, objectives, difficulty, status)
       VALUES (?, ?, ?, ?, ?, 'draft')
       RETURNING *`
    )
    .get(documentId, plan.title, plan.description, objectivesJson, plan.difficulty) as LessonPlanRow

  return rowToPlan(res)
}

export async function revisePlan(planId: number, feedback: string) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status !== 'draft') {
    throw new BadRequestError('Only draft lesson plans can be revised')
  }

  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(row.document_id) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (!doc.markdown) throw new BadRequestError('Document has no markdown content')

  const plan = await generatePlan(doc.markdown, doc.filename, feedback)
  const objectivesJson = JSON.stringify(plan.objectives)

  // Discard any quizzes generated for the previous draft.
  db.prepare(`DELETE FROM quiz_questions WHERE lesson_plan_id = ?`).run(planId)

  const updated = db
    .prepare(
      `UPDATE lesson_plans
       SET title = ?, description = ?, objectives = ?, difficulty = ?, revision_count = revision_count + 1, revision_feedback = ?
       WHERE id = ?
       RETURNING *`
    )
    .get(plan.title, plan.description, objectivesJson, plan.difficulty, feedback, planId) as LessonPlanRow

  return rowToPlan(updated)
}

export async function getPlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) return null
  const doc = db.prepare(`SELECT filename FROM documents WHERE id = ?`).get(row.document_id)
  return {
    ...rowToPlan(row),
    document_filename: (doc as { filename: string } | undefined)?.filename
  }
}

export async function getPlansForDocument(documentId: number) {
  const rows = db
    .prepare(`SELECT * FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC`)
    .all(documentId) as LessonPlanRow[]
  return rows.map(rowToPlan)
}

export async function approvePlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status === 'draft') {
    await createAllQuizzes(planId)
  }
  return getPlan(planId)
}

function rowToPlan(row: LessonPlanRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as Difficulty,
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as PlanStatus,
    revision_count: row.revision_count,
    revision_feedback: row.revision_feedback,
    created_at: row.created_at
  }
}

import { createAgent } from 'langchain'
import { model } from './model.ts'
import { quizSchema, batchQuizSchema, type Quiz, type BatchQuiz } from './schemas.ts'

const SYSTEM = `You are a meticulous quiz author. Build a single multiple-choice question that rigorously tests ONE learning objective using ONLY information present in the provided PDF markdown.

Rules:
- The question must be grounded in the document. Do not invent facts.
- Exactly 4 options. All options should be plausible; distractors should reflect common misconceptions.
- The correct option must be unambiguous given the source material.
- The explanation must justify the correct answer using the source.
- The hint must be conceptual and NEVER reveal or hint at the correct option index or wording.
- When a question_index is provided, create a distinct question from any other index for the same objective. Vary the angle (e.g. definition, application, comparison, implication) so multiple questions on the same objective are not repetitive.`

const quizAgent = createAgent({
  model: model,
  systemPrompt: SYSTEM,
  responseFormat: quizSchema
})

export async function generateQuiz(
  markdown: string,
  objectiveText: string,
  objectiveTopic: string,
  questionIndex: number
): Promise<Quiz> {
  const message = `
Objective to assess: ${objectiveText}
Topic: ${objectiveTopic}
Question number for this objective: ${questionIndex + 1}
Source material (markdown):\n"""\n${markdown}\n"""
`
  const result = await quizAgent.invoke({
    messages: [{ role: 'user', content: message.trim() }]
  })
  return result.structuredResponse
}

const BATCH_SYSTEM = `You are a meticulous quiz author. Build ALL multiple-choice questions for the approved lesson plan using ONLY information present in the provided PDF markdown.

Rules:
- For each objective listed below, generate exactly the requested number of questions.
- Each question must rigorously test ONE learning objective.
- Every question must be grounded in the document. Do not invent facts.
- Exactly 4 options per question. All options should be plausible; distractors should reflect common misconceptions.
- The correct option must be unambiguous given the source material.
- Each explanation must justify the correct answer using the source.
- Each hint must be conceptual and NEVER reveal or hint at the correct option index or wording.
- Within the same objective, vary the angle (e.g. definition, application, comparison, implication) so questions are not repetitive.
- Return the questions ordered by objective_index ascending, then question_index ascending.
- Use the exact objective_index and question_index values provided below.`

const batchQuizAgent = createAgent({
  model: model,
  systemPrompt: BATCH_SYSTEM,
  responseFormat: batchQuizSchema
})

export interface ObjectiveSpec {
  text: string
  topic: string
  question_count: number
}

export async function generateAllQuizzes(markdown: string, objectives: ObjectiveSpec[]): Promise<BatchQuiz> {
  const objectiveList = objectives
    .map((o, i) => {
      const questions = Array.from({ length: o.question_count }, (_, q) => `    - question ${q + 1} → question_index ${q}`).join('\n')
      return `  ${i}. ${o.text} [topic: ${o.topic}]\n    questions needed: ${o.question_count}\n${questions}`
    })
    .join('\n')

  const message = `
Objectives to assess (generate exactly the number of questions shown for each):\n${objectiveList}

Source material (markdown):\n"""\n${markdown}\n"""
`
  const result = await batchQuizAgent.invoke({
    messages: [{ role: 'user', content: message.trim() }]
  })
  return result.structuredResponse
}

